import React, { useRef } from "react"
import { Link } from "gatsby"

const demo1 = "/videos/saas_console.mp4"
const demo2 = "/videos/ai_agents.mp4"
const demo3 = "/videos/dcms.mp4"
const demo4 = "/videos/reqon-demo.mp4"

const DemoCard = () => {
  const videoRefs = useRef([])

  const demoVideos = [
    {
      id: 1,
      title: "Prototype: AI Autonomous Web QA Platform",
      videoSrc: demo4,
      detailsPage: "/demos/ai-autonomous-web-qa-platform",
    },
    {
      id: 2,
      title: "MVP: B2B SaaS Console for Advanced Ransomware Protection",
      videoSrc: demo1,
      detailsPage: "/demos/b2b-saas-console-for-advanced-ransomware-protection",
    },
    {
      id: 3,
      title: "MVP: B2B SaaS Platform for AI alignment as a service",
      videoSrc: demo2,
      detailsPage: "/demos/b2b-saas-platform-for-ai-alignment-as-a-service",
    },
    {
      id: 4,
      title: "Prototype: Debt Collection Management System",
      videoSrc: demo3,
      detailsPage: "/demos/debt-collection-management-system",
    },
  ]

  const handleVideoError = index => {
    console.error(`Video ${index} failed to load`)
  }

  const handleMouseEnter = async index => {
    const video = videoRefs.current[index]
    if (video) {
      try {
        video.currentTime = 0
        await video.play()
      } catch (error) {
        console.log("Play prevented:", error.message)
      }
    }
  }

  const handleMouseLeave = index => {
    const video = videoRefs.current[index]
    if (video) {
      video.pause()
      video.currentTime = 0
    }
  }

  const handleKeyDown = (event, index) => {
    if (event.key === "Enter" || event.key === " ") {
      videoRefs.current[index].play()
    }
  }

  return (
    <div className="row justify-content-center g-6" id="demo-videos">
      {demoVideos.map((video, index) => (
        <div key={video.id} className="col-lg-5 col-md-6">
          <div
            className="single-blog-post height-90 bg-fffbf5"
            role="button"
            tabIndex={0}
            onMouseEnter={() => handleMouseEnter(index)}
            onMouseLeave={() => handleMouseLeave(index)}
            onKeyDown={e => handleKeyDown(e, index)}
          >
            <div className="post-image">
              <Link to={video.detailsPage || "#"}>
                <video
                  ref={el => (videoRefs.current[index] = el)}
                  width="100%"
                  style={{
                    borderRadius: "8px",
                  }}
                  onContextMenu={e => e.preventDefault()}
                  controls={false}
                  muted
                  loop
                  playsInline
                  preload="metadata"
                  onError={() => handleVideoError(index)}
                >
                  <source src={video.videoSrc} type="video/mp4" />
                  Your browser does not support the video tag.
                </video>
              </Link>
            </div>
            <div className="post-content d-flex justify-content-center text-center">
              <h3>
                <Link to={video.detailsPage || "#"}>{video.title}</Link>
              </h3>
            </div>
          </div>
        </div>
      ))}
    </div>
  )
}

export default DemoCard
